#include <iostream>
#include <string>

class Vehicle {
public:
    virtual void print(std::ostream& out) const { out << "Vehicle"; }
    virtual ~Vehicle() = default;
    friend std::ostream& operator<<(std::ostream& out, const Vehicle& v) {
        v.print(out); return out;
    }
};

class Car : public Vehicle {
    std::string kind_;
public:
    Car(const std::string& k) : kind_(k) {}
    void print(std::ostream& out) const override { out << "Car: " << kind_; }
};

class Bike : public Vehicle {
    std::string style_;
public:
    Bike(const std::string& s) : style_(s) {}
    void print(std::ostream& out) const override { out << "Bike: " << style_; }
};

int main() {
    Vehicle v;
    Car c{"sedan"};
    Bike b{"mountain"};
    Vehicle* arr[3] = {&v, &c, &b};
    for (int i = 0; i < 3; ++i)
        std::cout << *arr[i] << "\n";
    return 0;
}

