solution_code:
#include <iostream>
#include <string>

class Entity { public: virtual ~Entity() = default; };
class Player : public Entity {};
class Enemy  : public Entity {};
class NPC    : public Entity {};

std::string identifyType(Entity* e) {
    if (dynamic_cast<Player*>(e)) return "Player";
    if (dynamic_cast<Enemy*>(e))  return "Enemy";
    if (dynamic_cast<NPC*>(e))    return "NPC";
    return "Unknown";
}

int main() {
    int n;
    std::cin >> n;
    if (n == 1) { Player p; std::cout << identifyType(&p) << "\n"; }
    else if (n == 2) { Enemy e;  std::cout << identifyType(&e) << "\n"; }
    else             { NPC np;   std::cout << identifyType(&np) << "\n"; }
    return 0;
}
